function latestUserText() {
  const msgs = board.channel(board.MAIN_CHANNEL) || [];
  for (let i = msgs.length - 1; i >= 0; i--) {
    const msg = msgs[i] || {};
    if (msg.role !== "user") continue;
    const parts = Array.isArray(msg.parts) ? msg.parts : [];
    const text = parts.map(function(part) {
      return part && part.type === "text" && typeof part.text === "string" ? part.text : "";
    }).join("").trim();
    if (text) return text;
  }
  return "";
}

const ws = board.getVar("workspace_state") || {};
const activeRoute = board.getVar("active_route") || ws.active_route || "";
const activeArgs = board.getVar("active_args") || ws.active_args || {};
const pendingRoutes = board.getVar("pending_routes") || ws.pending_routes || [];

if (activeRoute) {
  const args = Object.assign({}, activeArgs || {});
  const latest = latestUserText();
  if ((activeRoute === "play_music" || activeRoute === "play_song" || activeRoute === "sing") && !args.title && latest) {
    args.title = latest;
  }
  if (activeRoute === "read_story" && !args.title && !args.series && !args.subject && latest) {
    args.subject = latest;
  }
  board.setVar("route_source", "state");
  board.setVar("matched_intent", activeRoute);
  board.setVar("matched_args", args);
  board.setVar("matched_args_json", JSON.stringify(args || {}));
  board.setVar("function_route", activeRoute);
  board.setVar("pending_routes", Array.isArray(pendingRoutes) ? pendingRoutes : []);
  board.setVar("pending_routes_json", JSON.stringify(Array.isArray(pendingRoutes) ? pendingRoutes : []));
  board.setVar("has_next_route", false);
  board.setVar("has_function_intent", true);
  board.setVar("needs_format", false);
} else {
  board.setVar("route_source", "format");
  board.setVar("matched_intent", "");
  board.setVar("matched_args", {});
  board.setVar("matched_args_json", "{}");
  board.setVar("function_route", "");
  board.setVar("pending_routes", []);
  board.setVar("pending_routes_json", "[]");
  board.setVar("has_next_route", false);
  board.setVar("has_function_intent", false);
  board.setVar("needs_format", true);
  board.setVar("tmp_main_channel_before_format", board.channel(board.MAIN_CHANNEL));
  board.setChannel("route_format_channel", [{
    role: "user",
    parts: [{ type: "text", text: latestUserText() }],
  }]);
}

const raw = String(board.getVar("formatch_text") || "").trim();
const lines = raw.split(/\r?\n/).map(function(line) {
  return line.trim();
}).filter(Boolean);

function parseArgs(text) {
  const args = {};
  text.split(",").forEach(function(part) {
    const idx = part.indexOf("=");
    if (idx < 0) return;
    const key = part.slice(0, idx).trim();
    const value = part.slice(idx + 1).trim();
    if (key) args[key] = value;
  });
  return args;
}

const allowed = {
  play_song: true,
  sing: true,
  play_music: true,
  read_story: true,
  adjust_device_volume: true,
  stop_playing: true,
  stop_chat: true,
};

function routeFromIntent(intent) {
  let functionRoute = intent;
  if (intent === "play_song" || intent === "sing") functionRoute = "play_music";
  if (intent === "stop_playing" || intent === "stop_chat") functionRoute = "stop";
  return functionRoute;
}

function parseRoute(line) {
  if (line === "nothing") return null;
  const arrowIdx = line.indexOf("->");
  const normalized = arrowIdx >= 0 ? line.slice(arrowIdx + 2).trim() : line;
  const idx = normalized.indexOf(":");
  let intent = "";
  let args = {};
  if (idx < 0) {
    intent = normalized.trim();
  } else {
    intent = normalized.slice(0, idx).trim();
    args = parseArgs(normalized.slice(idx + 1));
  }
  if (!allowed[intent]) return null;
  return {
    intent: intent,
    route: routeFromIntent(intent),
    args: args,
  };
}

const routes = [];
for (const line of lines) {
  const parsed = parseRoute(line);
  if (parsed) routes.push(parsed);
}

if (routes.length === 0) {
  board.setVar("route_source", "chat");
  board.setVar("has_function_intent", false);
  board.setVar("matched_intent", "");
  board.setVar("matched_args", {});
  board.setVar("matched_args_json", "{}");
  board.setVar("function_route", "");
  board.setVar("pending_routes", []);
  board.setVar("pending_routes_json", "[]");
  board.setVar("has_next_route", false);
  board.setVar("needs_format", false);
} else {
  const current = routes[0];
  const pending = routes.slice(1);
  board.setVar("has_function_intent", true);
  board.setVar("route_source", "format");
  board.setVar("matched_intent", current.intent);
  board.setVar("matched_args", current.args || {});
  board.setVar("matched_args_json", JSON.stringify(current.args || {}));
  board.setVar("function_route", current.route);
  board.setVar("pending_routes", pending);
  board.setVar("pending_routes_json", JSON.stringify(pending));
  board.setVar("has_next_route", pending.length > 0);
}

const originalMain = board.getVar("tmp_main_channel_before_format");
if (Array.isArray(originalMain)) {
  board.setChannel(board.MAIN_CHANNEL, originalMain);
}

parallel.cancelNode("chat_buffer", "function route selected");

function latestUserText() {
  const msgs = board.channel(board.MAIN_CHANNEL) || [];
  for (let i = msgs.length - 1; i >= 0; i--) {
    const msg = msgs[i] || {};
    if (msg.role !== "user") continue;
    const parts = Array.isArray(msg.parts) ? msg.parts : [];
    const text = parts.map(function(part) {
      return part && part.type === "text" && typeof part.text === "string" ? part.text : "";
    }).join("").trim();
    if (text) return text;
  }
  return "";
}

const intent = String(board.getVar("matched_intent") || "");
const route = String(board.getVar("function_route") || intent || "");
const args = board.getVar("matched_args") || {};
const pending = Array.isArray(board.getVar("pending_routes")) ? board.getVar("pending_routes") : [];
const argsJSON = JSON.stringify(args || {});
const pendingJSON = JSON.stringify(pending);
board.setVar("matched_args_json", argsJSON);
board.setVar("pending_routes_json", pendingJSON);

const context = [
  "You are a function node in a routed assistant graph.",
  "Current route context:",
  "- intent: " + intent,
  "- route: " + route,
  "- matched_args_json: " + argsJSON,
  "- pending_routes_json: " + pendingJSON,
  "Use matched_args_json as the source of truth for the current function. Ignore earlier conversation, previous function output, and tool results if they conflict with this context.",
  "Complete only the current function. Do not mention or execute pending routes."
];
board.setVar("function_context", context.join("\n"));
board.setChannel("function_route_channel", [{
  role: "user",
  parts: [{ type: "text", text: latestUserText() }],
}]);

const intent = board.getVar("matched_intent") || "";
const route = board.getVar("function_route") || intent;
const args = board.getVar("matched_args") || {};
const pending = Array.isArray(board.getVar("pending_routes")) ? board.getVar("pending_routes") : [];
const missingTitle = (route === "play_music" || route === "read_story") && !args.title && !args.series && !args.subject;

if (missingTitle) {
  board.setVar("active_route", route);
  board.setVar("active_args", args);
  board.setVar("pending_routes", pending);
  board.setVar("matched_args_json", JSON.stringify(args || {}));
  board.setVar("pending_routes_json", JSON.stringify(pending));
  board.setVar("has_next_route", false);
} else if (pending.length > 0) {
  const next = pending[0] || {};
  const rest = pending.slice(1);
  board.setVar("route_source", "pending");
  board.setVar("matched_intent", next.intent || "");
  board.setVar("matched_args", next.args || {});
  board.setVar("matched_args_json", JSON.stringify(next.args || {}));
  board.setVar("function_route", next.route || "");
  board.setVar("active_route", "");
  board.setVar("active_args", {});
  board.setVar("pending_routes", rest);
  board.setVar("pending_routes_json", JSON.stringify(rest));
  board.setVar("has_next_route", true);
} else {
  board.setVar("active_route", "");
  board.setVar("active_args", {});
  board.setVar("pending_routes", []);
  board.setVar("matched_intent", "");
  board.setVar("matched_args", {});
  board.setVar("matched_args_json", "{}");
  board.setVar("function_route", "");
  board.setVar("pending_routes_json", "[]");
  board.setVar("has_function_intent", false);
  board.setVar("has_next_route", false);
}
